function parseContentToTitle(content: string, maxLength = 100) {
  if (!content || typeof content !== 'string') {
    return '';
  }

  let text = content.replace(/<[^>]*>?/gm, '');

  text = text
    .replace(/\\begin\{cases\}/g, 'Hệ: ')
    .replace(/\\end\{cases\}/g, '')

    .replace(/\\begin\{[^}]+\}/g, '')
    .replace(/\\end\{[^}]+\}/g, '')

    .replace(/\\\\/g, '; ')

    .replace(/\\left/g, '')
    .replace(/\\right/g, '');

  text = text
    .replace(/\\frac\{([^}]+)\}\{([^}]+)\}/g, '$1/$2')
    .replace(/\\sqrt\{([^}]+)\}/g, '√$1')
    .replace(/\\sqrt\[([^\]]+)\]\{([^}]+)\}/g, '$1√$2')
    .replace(/\\widehat\{([^}]+)\}/g, 'góc $1')
    .replace(/\\overparen\{([^}]+)\}/g, 'cung $1')
    .replace(/\\text\{([^}]+)\}/g, '$1');

  const latexMap: { [key: string]: string } = {
    '\\le': '≤',
    '\\ge': '≥',
    '\\ne': '≠',
    '\\approx': '≈',
    '\\pm': '±',
    '\\mp': '∓',
    '\\times': '×',
    '\\cdot': '·',
    '\\div': '÷',
    '\\in': '∈',
    '\\notin': '∉',
    '\\subset': '⊂',
    '\\perp': '⊥',
    '\\parallel': '//',
    '\\infty': '∞',
    '\\circ': '°',
    '^\\circ': '°',
    '\\Rightarrow': '=>',
    '\\Leftrightarrow': '<=>',

    '\\alpha': 'α',
    '\\beta': 'β',
    '\\gamma': 'γ',
    '\\delta': 'δ',
    '\\pi': 'π',
    '\\theta': 'θ',
    '\\lambda': 'λ',
    '\\mu': 'μ',
    '\\rho': 'ρ',
    '\\sigma': 'σ',
    '\\omega': 'ω',
    '\\Delta': 'Δ',
    '\\Omega': 'Ω',
    '\\Sigma': 'Σ',

    '\\mathbb{R}': 'R',
    '\\mathbb{N}': 'N',
    '\\mathbb{Z}': 'Z',
    '\\mathbb{Q}': 'Q',
  };

  for (const [key, value] of Object.entries(latexMap)) {
    const escapedKey = key.replace(/\\/g, '\\\\').replace(/\^/g, '\\^');
    const regex = new RegExp(escapedKey, 'g');
    text = text.replace(regex, value);
  }

  text = text
    .replace(/\$/g, '')
    .replace(/[\{\}]/g, '')
    .replace(/\^/g, '')
    .replace(/_/g, '')
    .replace(/\\/g, '')
    .replace(/\s+/g, ' ')
    .trim();

  if (cleanedContent(text).length === 0) return 'Câu hỏi hình ảnh/công thức';

  if (text.length <= maxLength) {
    return text;
  }

  let shortenedTitle = text.substring(0, maxLength);
  let lastSpace = shortenedTitle.lastIndexOf(' ');
  if (lastSpace > 0) {
    shortenedTitle = shortenedTitle.substring(0, lastSpace);
  }

  return shortenedTitle + '...';
}

function cleanedContent(text: string) {
  return text.replace(/\s/g, '');
}
function formatQuillContent(text) {
  if (!text) return null;

  const latexBlocks = [];
  
  // 1. Trích xuất và bảo vệ LaTeX (không để các bước sau đụng vào)
  let html = text.replace(/\$(.*?)\$/gs, (match, latexCode) => {
    const placeholder = `__LATEX_PLACEHOLDER_${latexBlocks.length}__`;
    latexBlocks.push({
      original: match,
      code: latexCode
    });
    return placeholder;
  });

  // 2. Xử lý xuống dòng và đoạn văn cho phần text còn lại
  const paragraphs = html.split(/\n\n+/);
  html = paragraphs
    .map(para => {
      const inner = para.replace(/\n/g, '<br>').trim();
      return inner ? `<p>${inner}</p>` : '<p><br></p>';
    })
    .join('');

  // 3. Trả lại LaTeX nguyên bản vào đúng vị trí, bọc trong tag của Quill
  latexBlocks.forEach((item, index) => {
    const placeholder = `__LATEX_PLACEHOLDER_${index}__`;
    // Lưu ý: data-value phải là code sạch, không có <br>
    const formulaHtml = `<span class="ql-formula" data-value="${item.code.replace(/"/g, '&quot;').trim()}">${item.code.trim()}</span>`;
    html = html.replace(placeholder, formulaHtml);
  });

  return html;
}

const createAnswersData = (answers) => {
  return answers.map((ans, index) => ({
    aid: index + 1,
    content: formatQuillContent(ans.content),
    is_correct: ans.is_correct,
    explaination: ans.explaination
      ? formatQuillContent(ans.explaination)
      : null,
  }));
};

